85	// Run invokes a single agent harness and returns the result.
86	func (r *Runner) Run(opts RunOptions) (*Result, error) {
87		harness, harnessName, err := r.resolveHarness(opts)
88		if err != nil {
89			return nil, err
90		}
91	
92		// If the provider flag was consumed as a harness name (e.g. "agent",
93		// "local"), clear it so downstream code (RunAgent →
94		// resolveEmbeddedAgentProvider) doesn't try to look it up as a
95		// ddx-agent config provider name.
96		if opts.Provider != "" {
97			resolved := resolveHarnessAlias(opts.Provider)
98			if resolved == harnessName {
99				opts.Provider = ""
100			}
101		}
102	
103		// virtual harness: replay from dictionary instead of executing a binary.
104		if harnessName == "virtual" {
105			return runVirtualFn(r, opts)
106		}
107	
108		// Agent harness: run in-process via the embedded agent library.
109		if harnessName == "agent" {
110			return RunAgent(r, opts)
111		}
112	
113		// Script harness: execute directives against the real filesystem and git.
114		if harnessName == "script" {
115			return runScriptFn(r, opts)
116		}
117	
118		// HTTP-provider harnesses (lmstudio, openrouter, and any other harness
119		// registered with IsHTTPProvider=true and no Binary) have no CLI binary
120		// to exec. They MUST route through the embedded agent runtime, which
121		// speaks OpenAI-compatible APIs and can be pointed at any provider via
122		// --provider. Without this dispatch, the exec path below would call
123		// ExecuteInDir with harness.Binary="", producing a zero-duration
124		// "exec: no command" error (see ddx-501e87ef: cheap-tier attempts on
125		// lmstudio were burning <1s and escalating straight to smart tier).
126		if harness.IsHTTPProvider && harness.Binary == "" {
127			agentOpts := opts
128			// Surface the harness name as the provider so the embedded runtime
129			// knows which .agent/config.yaml provider block to use. If the caller
130			// already specified --provider, preserve their choice.
131			if agentOpts.Provider == "" {
132				agentOpts.Provider = harnessName
133			}
134			return RunAgent(r, agentOpts)
135		}
136	
137		prompt, err := r.resolvePrompt(opts)
138		if err != nil {
139			return nil, err
140		}
141	
142		model := r.resolveModel(opts, harnessName)
143	
144		// Warn on deprecated explicit model pin.
145		if model != "" {
146			cat := r.catalog()
147			if dp, deprecated := cat.CheckDeprecatedPin(model, harness.Surface); deprecated {
148				fmt.Fprintf(os.Stderr, "agent: model %q is deprecated; use %q instead\n", model, dp.ReplacedBy)
149			}
150		}
151	
152		// Warn on unknown model
153		if model != "" && len(harness.Models) > 0 && !containsString(harness.Models, model) {
154			fmt.Fprintf(os.Stderr, "agent: model %q is not a known model for harness %q; available models: %s\n",
155				model, harnessName, strings.Join(harness.Models, ", "))
156		}
157	
158		// Warn on unknown effort
159		if opts.Effort != "" {
160			levels := r.resolveReasoningLevels(harnessName, harness)
161			if len(levels) > 0 && !containsString(levels, opts.Effort) {
162				fmt.Fprintf(os.Stderr, "agent: effort %q is not a known reasoning level for harness %q; available levels: %s\n",
163					opts.Effort, harnessName, strings.Join(levels, ", "))
164			}
165		}
166	
167		timeout := r.resolveTimeout(opts)
168		wallClock := r.resolveWallClock(opts)
169	
170		// Build args with the resolved prompt (may have come from file)
171		resolvedOpts := opts
172		// evidence:allow-unbounded reason="prompt is the bounded output of r.resolvePrompt → readPromptFileBounded (FEAT-022 §3)"
173		resolvedOpts.Prompt = prompt
174		resolvedOpts.Permissions = resolvePermissions(r.Config.Permissions, opts.Permissions)
175		args := BuildArgs(harness, resolvedOpts, model)
176		stdin := ""
177		if harness.PromptMode == "stdin" {
178			stdin = prompt
179		}
180	
181		// Execute
182		start := time.Now()
183		parentCtx := opts.Context
184		if parentCtx == nil {
185			parentCtx = context.Background()
186		}
187		ctx, cancel := context.WithCancel(parentCtx)
188		defer cancel()
189		ctx = withExecutionTimeout(ctx, timeout)
190		ctx = withExecutionWallClock(ctx, wallClock)
191	
192		// Use ExecuteInDir when WorkDir is set — this handles harnesses like
193		// claude that have no --cwd flag by setting cmd.Dir on the subprocess.
194		execDir := ""
195		if opts.WorkDir != "" && harness.WorkDirFlag == "" {
196			execDir = opts.WorkDir
197		}
198	
199		// Claude streaming path: when running against the real OSExecutor, pipe
200		// claude's stream-json stdout through parseClaudeStream so operators see
201		// real-time progress (tool calls, turn counts, elapsed) in
202		// `ddx server workers log` instead of a 20–40 minute silence. The path
203		// falls back to the legacy buffered --print behaviour automatically if
204		// the CLI rejects the stream-json flags.
205		if harnessName == "claude" {
206			if _, isOS := r.Executor.(*OSExecutor); isOS {
207				result, err := runClaudeWithFallbackFn(r, ctx, harness, harnessName, model, resolvedOpts, prompt, execDir, timeout)
208				if err == nil && result != nil {
209					finalizeClaudeResult(r, result, opts, prompt, time.Since(start))
210					return result, nil
211				}
212				// If the streaming path failed outright (not just claude exit != 0),
213				// fall through to the classic Executor path so behaviour degrades
214				// gracefully.
215			}
216		}
217	
218		execResult, execErr := r.Executor.ExecuteInDir(ctx, harness.Binary, args, stdin, execDir)
219		elapsed := time.Since(start)
220	
221		result := r.processResult(harnessName, model, harness, execResult, execErr, elapsed, ctx)
222		promptSource := opts.PromptSource
223		if promptSource == "" {
224			if opts.PromptFile != "" {
225				promptSource = opts.PromptFile
226			} else {
227				promptSource = "inline"
228			}
229		}
230		r.logSession(result, len(prompt), prompt, promptSource, opts.Correlation)
231		r.recordRoutingOutcome(result, elapsed, opts)
232		return result, nil
233	}
