416	// resolveTimeout picks the idle (inactivity) timeout from opts or config.
417	func (r *Runner) resolveTimeout(opts RunOptions) time.Duration {
418		if opts.Timeout > 0 {
419			return opts.Timeout
420		}
421		return time.Duration(r.Config.TimeoutMS) * time.Millisecond
422	}
