485	// processResult converts execution output to a Result.
486	func (r *Runner) processResult(harnessName, model string, harness harnessConfig, execResult *ExecResult, execErr error, elapsed time.Duration, ctx context.Context) *Result {
487		result := &Result{
488			Harness:    harnessName,
489			Model:      model,
490			DurationMS: int(elapsed.Milliseconds()),
491		}
492	
493		if execResult != nil {
494			result.Output = execResult.Stdout
495			result.Stderr = execResult.Stderr
496			result.ExitCode = execResult.ExitCode
497		}
498	
499		if execResult != nil && execResult.EarlyCancel {
500			result.Error = fmt.Sprintf("cancelled: auth/rate-limit detected (%s)", execResult.CancelReason)
501			result.ExitCode = -1
502		} else if execResult != nil && execResult.WallClockTimeout {
503			// Wall-clock cap fired regardless of stream activity; distinguish
504			// this from the resettable idle timer so operators can tell the two
505			// failure modes apart in result.json and session logs.
506			reportedElapsed := execResult.WallClockElapsed
507			if reportedElapsed == 0 {
508				reportedElapsed = elapsed
509			}
510			result.Error = fmt.Sprintf("wall-clock deadline exceeded after %v", reportedElapsed.Round(time.Second))
511			result.ExitCode = -1
512		} else if execErr != nil {
513			if errors.Is(execErr, context.DeadlineExceeded) || errors.Is(ctx.Err(), context.DeadlineExceeded) {
514				result.Error = fmt.Sprintf("timeout after %v", elapsed.Round(time.Second))
515				result.ExitCode = -1
516			} else {
517				result.Error = execErr.Error()
518				if result.ExitCode == 0 {
519					result.ExitCode = -1
520				}
521			}
522		} else if execResult != nil && execResult.ExitCode != 0 {
523			result.Error = execResult.Stderr
524		}
525	
526		result.Tokens = ExtractTokens(result.Output, harness)
527		usage := ExtractUsage(harnessName, result.Output)
528		result.InputTokens = usage.InputTokens
529		result.OutputTokens = usage.OutputTokens
530		result.CostUSD = usage.CostUSD
531		return result
532	}
