880	// logSession writes a session entry to the log directory.
881	func (r *Runner) logSession(result *Result, promptLen int, prompt, promptSource string, correlation map[string]string) {
882		dir := r.Config.SessionLogDir
883		if dir == "" {
884			return
885		}
886	
887		if err := os.MkdirAll(dir, 0o755); err != nil {
888			return // best effort
889		}
890	
891		id := genSessionID()
892		var surface string
893		canonicalTarget := result.Model
894		if harness, ok := r.registry.Get(result.Harness); ok {
895			surface = harness.Surface
896			if canonicalTarget == "" {
897				canonicalTarget = harness.DefaultModel
898			}
899		}
900		if canonicalTarget == "" {
901			canonicalTarget = result.Harness
902		}
903		entry := SessionEntry{
904			ID:              id,
905			Timestamp:       time.Now().UTC(),
906			Harness:         result.Harness,
907			Provider:        result.Provider,
908			Surface:         surface,
909			CanonicalTarget: canonicalTarget,
910			BaseURL:         result.ResolvedBaseURL,
911			BillingMode:     billingModeFor(result.Harness, surface, result.ResolvedBaseURL),
912			Model:           result.Model,
913			PromptLen:       promptLen,
914			Prompt:          prompt,
915			PromptSource:    promptSource,
916			Response:        result.Output,
917			Correlation:     correlation,
918			NativeSessionID: result.AgentSessionID,
919			Stderr:          result.Stderr,
920			Tokens:          result.Tokens,
921			InputTokens:     result.InputTokens,
922			OutputTokens:    result.OutputTokens,
923			TotalTokens:     result.InputTokens + result.OutputTokens,
924			CostUSD:         result.CostUSD,
925			Duration:        result.DurationMS,
926			ExitCode:        result.ExitCode,
927			Error:           result.Error,
928		}
929	
930		if entry.NativeSessionID == "" && correlation != nil {
931			entry.NativeSessionID = correlation["native_session_id"]
932		}
933		if correlation != nil {
934			entry.NativeLogRef = correlation["native_log_ref"]
935			entry.TraceID = correlation["trace_id"]
936			entry.SpanID = correlation["span_id"]
937		}
938	
939		_ = AppendSessionIndex(dir, SessionIndexEntryFromLegacy("", entry), entry.Timestamp)
940	}
