332	// TestProviderConnectivityViaService runs a HealthCheck against the named
333	// harness and translates the result into a ProviderStatus. It is the
334	// production replacement for Runner.TestProviderConnectivity.
335	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
336		status := ProviderStatus{Reachable: false}
337		if ctx == nil {
338			ctx = context.Background()
339		}
340		if harnessName == "virtual" || harnessName == "agent" {
341			status.Reachable = true
342			status.CreditsOK = true
343			return status
344		}
345		svc, err := NewServiceFromWorkDir(workDir)
346		if err != nil {
347			status.Error = err.Error()
348			return status
349		}
350		if timeout > 0 {
351			var cancel context.CancelFunc
352			ctx, cancel = context.WithTimeout(ctx, timeout)
353			defer cancel()
354		}
355		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
356			errStr := strings.ToLower(err.Error())
357			status.Error = err.Error()
358			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
359				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
360				status.CreditsOK = false
361			}
362			return status
363		}
364		status.Reachable = true
365		status.CreditsOK = true
366		return status
367	}
