363	// cleanupCompareWorktrees removes the worktrees created for a compare run.
364	// Free function; both RunCompareViaService and RunCompareWithAgent route through
365	// this helper.
366	func cleanupCompareWorktrees(repoDir, compareID string) {
367		if root, err := resolveGitRoot(repoDir); err == nil {
368			repoDir = root
369		}
370		wtBase := filepath.Join(repoDir, ".worktrees")
371		entries, err := os.ReadDir(wtBase)
372		if err != nil {
373			return
374		}
375		for _, e := range entries {
376			if e.IsDir() && strings.HasPrefix(e.Name(), compareID) {
377				wtPath := filepath.Join(wtBase, e.Name())
378				cmd := internalgit.Command(context.Background(), repoDir, "worktree", "remove", "--force", wtPath)
379				_ = cmd.Run()
380			}
381		}
382		cmd := internalgit.Command(context.Background(), repoDir, "worktree", "prune")
383		_ = cmd.Run()
384	}
