20	// VirtualEntry represents a recorded prompt→response pair stored on disk.
21	type VirtualEntry struct {
22		PromptHash   string  `json:"prompt_hash"`
23		PromptLen    int     `json:"prompt_len"`
24		Prompt       string  `json:"prompt"`
25		Response     string  `json:"response"`
26		ExitCode     int     `json:"exit_code,omitempty"`
27		Harness      string  `json:"harness"`
28		Model        string  `json:"model,omitempty"`
29		DelayMS      int     `json:"delay_ms"`
30		InputTokens  int     `json:"input_tokens,omitempty"`
