32		CostUSD      float64 `json:"cost_usd,omitempty"`
33		RecordedAt   string  `json:"recorded_at"`
34	}
35	
36	// InlineResponse is a single entry in the DDX_VIRTUAL_RESPONSES env var.
37	// It uses pattern-based matching (substring or regex) instead of hash-based.
38	type InlineResponse struct {
39		PromptMatch string `json:"prompt_match"`        // substring or /regex/ pattern
40		Response    string `json:"response"`            // response text
41		ExitCode    int    `json:"exit_code,omitempty"` // simulated exit code
42		Model       string `json:"model,omitempty"`     // optional model name
43		DelayMS     int    `json:"delay_ms,omitempty"`  // optional simulated delay
44	}
45	
46	// LookupInline searches inline responses for a matching prompt.
47	// prompt_match is treated as a regex if wrapped in /.../, otherwise substring.
48	func LookupInline(responses []InlineResponse, prompt string) (*InlineResponse, bool) {
49		for i := range responses {
50			r := &responses[i]
51			match := r.PromptMatch
52			if len(match) >= 2 && match[0] == '/' && match[len(match)-1] == '/' {
53				// Regex match
54				re, err := regexp.Compile(match[1 : len(match)-1])
55				if err != nil {
56					continue
57				}
58				if re.MatchString(prompt) {
59					return r, true
60				}
61			} else {
62				// Substring match
63				if strings.Contains(prompt, match) {
64					return r, true
65				}
66			}
67		}
68		return nil, false
69	}
70	
71	// NormalizePrompt applies configured regex→replacement patterns to a prompt
72	// before hashing. This allows prompts with dynamic content (temp paths,
73	// timestamps, bead IDs) to produce stable hashes across runs.
74	func NormalizePrompt(prompt string, patterns []config.NormalizePattern) string {
75		for _, p := range patterns {
76			re, err := regexp.Compile(p.Pattern)
77			if err != nil {
78				continue // skip invalid patterns
79			}
80			prompt = re.ReplaceAllString(prompt, p.Replace)
81		}
82		return prompt
83	}
84	
85	// PromptHash computes a truncated SHA-256 hash of a prompt for use as a
86	// dictionary filename. The hash is 16 hex characters (64 bits), which is
87	// sufficient to avoid collisions in practice while keeping filenames readable.
88	func PromptHash(prompt string) string {
89		h := sha256.Sum256([]byte(prompt))
90		return hex.EncodeToString(h[:8])
91	}
92	
93	// RecordEntry saves a prompt→response pair to the dictionary directory.
94	// If normalize patterns are provided, they are applied before hashing.
95	func RecordEntry(dictDir string, entry *VirtualEntry, patterns ...config.NormalizePattern) error {
96		if err := os.MkdirAll(dictDir, 0755); err != nil {
97			return fmt.Errorf("creating dictionary dir: %w", err)
98		}
99	
100		normalized := NormalizePrompt(entry.Prompt, patterns)
101		entry.PromptHash = PromptHash(normalized)
102		entry.PromptLen = len(entry.Prompt)
103		if entry.RecordedAt == "" {
104			entry.RecordedAt = time.Now().UTC().Format(time.RFC3339)
105		}
106	
107		data, err := json.MarshalIndent(entry, "", "  ")
108		if err != nil {
109			return fmt.Errorf("marshaling entry: %w", err)
110		}
111	
112		path := filepath.Join(dictDir, entry.PromptHash+".json")
113		if err := os.WriteFile(path, data, 0644); err != nil {
114			return fmt.Errorf("writing dictionary entry: %w", err)
115		}
116		return nil
117	}
